payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成仿生柔性传感材料微结构设计、液态金属-聚氨酯复合薄膜制备及信号标定，构建0.1mm级空间分辨率的混合传感架构，配备柔性材料合成设备与高精度采集平台。"
    },
    {
      "date": "第3月",
      "title": "算法开发与融合协议构建",
      "description": "开发分层CNN-LSTM手势识别模型，结合自适应滑动窗口分割与噪声抑制模块，实现实测>98.2%准确率；同步建立视觉-触觉-听觉统一时空对齐协议，提升跨平台部署效率60%。"
    },
    {
      "date": "第4月",
      "title": "系统集成与闭环搭建",
      "description": "完成软硬件联调，嵌入微型电磁致动器阵列与半导体温控模块，实现压力/温度微秒级调控；集成多模态交互协议栈，构建感知-意图-反馈闭环，并接入H-Box全息舱与李未可眼镜接口。"
    },
    {
      "date": "第5–6月",
      "title": "多场景验证与体验优化",
      "description": "在工业远程操控与虚拟实训等场景开展压力测试，通过用户反馈采集系统迭代优化交互性能，形成可复用的标准接口，完成工程化落地验证。"
    }
  ]
}

